    {"name": "GTJA_Alpha018", "description": "国泰君安Alpha#18: 5日价格比率", "formula": "close / delay(close, 5)", "category": "MOMENTUM", "sub_category": "TIME_SERIES_MOMENTUM", "direction": "POSITIVE", "source": "Alpha191"},
    {"name": "GTJA_Alpha019", "description": "国泰君安Alpha#19: 条件价格变化率", "formula": "if_else(close < delay(close, 5), (close - delay(close, 5)) / delay(close, 5), if_else(close == delay(close, 5), 0, (close - delay(close, 5)) / close))", "category": "MOMENTUM", "sub_category": "TIME_SERIES_MOMENTUM", "direction": "NEGATIVE", "source": "Alpha191"},
    {"name": "GTJA_Alpha020", "description": "国泰君安Alpha#20: 6日价格变化率百分比", "formula": "(close - delay(close, 6)) / delay(close, 6) * 100", "category": "MOMENTUM", "sub_category": "TIME_SERIES_MOMENTUM", "direction": "POSITIVE", "source": "Alpha191"},
