    {"name": "GTJA_Alpha022", "description": "国泰君安Alpha#22: 收盘价均线偏离变化SMA", "formula": "sma((close - ts_mean(close, 6)) / ts_mean(close, 6) - delay((close - ts_mean(close, 6)) / ts_mean(close, 6), 3), 12, 1)", "category": "TECHNICAL", "sub_category": "TREND_FACTOR", "direction": "POSITIVE", "source": "Alpha191"},
    {"name": "GTJA_Alpha023", "description": "国泰君安Alpha#23: 条件波动率SMA比率", "formula": "sma(if_else(close > delay(close, 1), ts_std(close, 20), 0), 20, 1) / (sma(if_else(close > delay(close, 1), ts_std(close, 20), 0), 20, 1) + sma(if_else(close <= delay(close, 1), ts_std(close, 20), 0), 20, 1)) * 100", "category": "VOLATILITY", "sub_category": "HISTORICAL_VOLATILITY", "direction": "POSITIVE", "source": "Alpha191"},
    {"name": "GTJA_Alpha024", "description": "国泰君安Alpha#24: 5日价格变化SMA", "formula": "sma(close - delay(close, 5), 5, 1)", "category": "MOMENTUM", "sub_category": "TIME_SERIES_MOMENTUM", "direction": "POSITIVE", "source": "Alpha191"},
