    {"name": "GTJA_Alpha026", "description": "国泰君安Alpha#26: 收盘价与均线偏离结合长期相关性", "formula": "ts_mean(close, 7) / 7 - close + ts_corr(vwap, delay(close, 5), 230)", "category": "TECHNICAL", "sub_category": "TREND_FACTOR", "direction": "POSITIVE", "source": "Alpha191"},
    {"name": "GTJA_Alpha027", "description": "国泰君安Alpha#27: 多期价格变化率加权平均", "formula": "wma((close - delay(close, 3)) / delay(close, 3) * 100 + (close - delay(close, 6)) / delay(close, 6) * 100, 12)", "category": "MOMENTUM", "sub_category": "TIME_SERIES_MOMENTUM", "direction": "POSITIVE", "source": "Alpha191"},
