    {"name": "GTJA_Alpha031", "description": "国泰君安Alpha#31: 收盘价与均线偏离百分比", "formula": "(close - ts_mean(close, 12)) / ts_mean(close, 12) * 100", "category": "TECHNICAL", "sub_category": "TREND_FACTOR", "direction": "NEGATIVE", "source": "Alpha191"},
