    {"name": "GTJA_Alpha033", "description": "国泰君安Alpha#33: 最低价变化与收益排名组合", "formula": "(-1 * ts_min(low, 5) + delay(ts_min(low, 5), 5)) * cs_rank((ts_sum(returns, 240) - ts_sum(returns, 20)) / 220) * ts_rank(volume, 5)", "category": "TECHNICAL", "sub_category": "PRICE_FACTOR", "direction": "NEGATIVE", "source": "Alpha191"},
    {"name": "GTJA_Alpha034", "description": "国泰君安Alpha#34: 收盘价与均线比率", "formula": "ts_mean(close, 12) / close", "category": "TECHNICAL", "sub_category": "TREND_FACTOR", "direction": "NEGATIVE", "source": "Alpha191"},
