    {"name": "GTJA_Alpha036", "description": "国泰君安Alpha#36: 成交量与VWAP排名相关性累积排名", "formula": "cs_rank(ts_sum(ts_corr(cs_rank(volume), cs_rank(vwap), 6), 2))", "category": "VOLUME", "sub_category": "VOLUME_FACTOR", "direction": "POSITIVE", "source": "Alpha191"},
