    {"name": "GTJA_Alpha038", "description": "国泰君安Alpha#38: 最高价与均线条件因子", "formula": "if_else(ts_mean(high, 20) < high, -1 * delta(high, 2), 0)", "category": "TECHNICAL", "sub_category": "TREND_FACTOR", "direction": "NEGATIVE", "source": "Alpha191"},
