    {"name": "GTJA_Alpha043", "description": "国泰君安Alpha#43: 条件成交量累积", "formula": "ts_sum(if_else(close > delay(close, 1), volume, if_else(close < delay(close, 1), -volume, 0)), 6)", "category": "VOLUME", "sub_category": "VOLUME_FACTOR", "direction": "POSITIVE", "source": "Alpha191"},
    {"name": "GTJA_Alpha044", "description": "国泰君安Alpha#44: 低价成交量相关性与VWAP变化衰减组合", "formula": "ts_rank(decay_linear(ts_corr(low, ts_mean(volume, 10), 7), 6), 4) + ts_rank(decay_linear(delta(vwap, 3), 10), 15)", "category": "VOLUME", "sub_category": "VOLUME_FACTOR", "direction": "POSITIVE", "source": "Alpha191"},
