    {"name": "GTJA_Alpha050", "description": "国泰君安Alpha#50: 成交量与VWAP排名相关性最大值", "formula": "-1 * ts_max(cs_rank(ts_corr(cs_rank(volume), cs_rank(vwap), 5)), 5)", "category": "VOLUME", "sub_category": "VOLUME_FACTOR", "direction": "NEGATIVE", "source": "Alpha191"},
