    {"name": "GTJA_Alpha053", "description": "国泰君安Alpha#53: 高低价收盘价位置变化", "formula": "-1 * delta(cs_rank((high - close) / (close - low + 0.001)), 1)", "category": "TECHNICAL", "sub_category": "PRICE_FACTOR", "direction": "NEGATIVE", "source": "Alpha191"},
