    {"name": "GTJA_Alpha060", "description": "国泰君安Alpha#60: 开盘价收盘价成交量相关性组合", "formula": "-1 * ts_rank(ts_corr(open, close, 10) * ts_corr(close, volume, 10) * ts_rank(delta(close, 1), 10), 10)", "category": "VOLUME", "sub_category": "VOLUME_FACTOR", "direction": "NEGATIVE", "source": "Alpha191"},
